26	  process.env.ARIZE_PROJECT_NAME ?? "twyne";
27	// Arize is region-sharded. The OTLP host is region-specific
28	// (otlp.<region>.arize.com); the US default would silently 401 a CA space.
29	// Override the full endpoint, or just the region, via env.
30	const ARIZE_REGION = process.env.ARIZE_REGION ?? "ca-central-1a";
