42	  provider = new NodeTracerProvider({
43	    resource: resourceFromAttributes({
44	      model_id: ARIZE_PROJECT_NAME,
45	      model_version: "1.0.0",
46	    }),
47	    spanProcessors: [
48	      new OpenInferenceSimpleSpanProcessor({
49	        exporter: new OTLPTraceExporter({
50	          url: ARIZE_OTLP_ENDPOINT,
51	          headers: {
52	            "arize-space-id": ARIZE_SPACE_ID as string,
53	            "arize-api-key": ARIZE_API_KEY as string,
54	          },
55	        }),
56	        spanFilter: isOpenInferenceSpan,
57	        reparentOrphanedSpans: true,
58	      }),
59	    ],
