137	    .replace(/&lt;/g, "<")
138	    .replace(/&gt;/g, ">")
139	    .replace(/&quot;/g, '"')
140	    .replace(/&#39;/g, "'")
141	    .replace(/[ \t]+/g, " ")
142	    .replace(/\n{3,}/g, "\n\n")
143	    .trim();
144	}
