353	export const head: DocumentHead = {
354	  title: "Begin the dossier · Twyne",
355	  meta: [
356	    {
357	      name: "description",
358	      content:
359	        "Twyne's onboarding interview: the dossier the room will read from as you write.",

1	import {
2	  component$,
3	  useStore,
4	  useSignal,
5	  $,
6	  type PropFunction,
7	  useVisibleTask$,
8	} from "@builder.io/qwik";
9	import {
10	  type InterviewMessage,
11	  type InterviewTurnResult,
12	  type InterviewConfidence,
13	  type InterviewDossierDraft,
14	  hasConfiguredAiProvider,
15	  runClientInterviewTurn,
16	} from "../../utils/ai-client";
17	import { loadAiSettingsFromIdb } from "../../utils/idb";
18	import type { ProjectBrief, ProjectInterviewAnswers } from "../../types";
19	import { useConvexClient } from "../../utils/convex-context";
20	import { api } from "../../../convex/_generated/api";
21	
22	/**
23	 * The conversational interview. A chat-style replacement for the
24	 * form: the AI asks one question at a time, the writer answers in
25	 * free text, the AI asks the next question, and when it has enough
26	 * the AI synthesises a dossier the writer can review and accept.
27	 *
28	 * Two modes:
29	 *   - "first-run" — no prior brief. The conversation starts from
30	 *     scratch.
31	 *   - "refine"    — the writer has a dossier already; the AI
32	 *     cross-references it during the conversation.
33	 *
34	 * Non-streaming. Streaming the AI's question into the chat is a
35	 * polish pass for later — the current implementation waits for the
36	 * full response before showing the next message.
37	 */
38	
39	const FIELD_LABELS: Record<keyof ProjectInterviewAnswers, string> = {
40	  workingTitle: "Working title",
41	  format: "Format",
42	  audience: "Audience",
43	  goal: "Goal",
44	  tone: "Tone",
45	  constraints: "Constraints",
46	  successSignal: "Success signal",
47	};
48	
49	const FIELD_ORDER: Array<keyof ProjectInterviewAnswers> = [
50	  "workingTitle",
51	  "format",
52	  "audience",
53	  "goal",
54	  "tone",
55	  "constraints",
56	  "successSignal",
57	];
58	
59	const OPENING_QUESTION =
60	  "Tell me the piece in one sentence — the way you'd describe it to a friend at lunch.";
61	
62	const REFINE_OPENING_QUESTION =
63	  "Reading your current brief back to you, what feels off, or what has the draft outgrown?";
64	
65	interface ConversationalInterviewProps {
66	  mode: "first-run" | "refine";
67	  initialBrief?: ProjectBrief;
68	  onComplete$: PropFunction<(brief: ProjectInterviewAnswers) => void>;
69	  onCancel$?: PropFunction<() => void>;
70	  cancelLabel?: string;
71	}
72	
73	interface Synthesis {
74	  brief: ProjectInterviewAnswers;
75	  confidence: Partial<
76	    Record<keyof ProjectInterviewAnswers, InterviewConfidence>
77	  >;
78	}
79	
80	interface ComponentStore {
81	  messages: InterviewMessage[];
82	  loading: boolean;
83	  error: string | null;
84	  synthesis: Synthesis | null;
85	  liveDraft: InterviewDossierDraft | null;
86	  /** When the writer edits a field of the synthesis before accepting. */
87	  editingField: keyof ProjectInterviewAnswers | null;
88	  draft: string;
89	  initialized: boolean;
90	}
91	
92	function confidenceTone(c: InterviewConfidence | undefined): string {
93	  if (c === "high") return "bg-[var(--color-accent-green)]";
94	  if (c === "low") return "bg-[var(--color-vermilion)]";
95	  return "bg-[var(--color-mustard)]";
96	}
97	
98	function confidenceLabel(c: InterviewConfidence | undefined): string {
99	  if (c === "high") return "high confidence";
100	  if (c === "low") return "low confidence";
101	  return "inferred";
102	}
103	
104	function mergeDossierDraft(
105	  current: InterviewDossierDraft | null,
106	  next: InterviewDossierDraft | undefined,
107	): InterviewDossierDraft | null {
108	  if (!next) return current;
109	  return {
110	    brief: { ...(current?.brief ?? {}), ...next.brief },
111	    confidence: { ...(current?.confidence ?? {}), ...next.confidence },
112	  };
113	}
114	
115	export const ConversationalInterview = component$(
116	  (props: ConversationalInterviewProps) => {
117	    const store = useStore<ComponentStore>({
118	      messages: [],
119	      loading: false,
120	      error: null,
121	      synthesis: null,
122	      liveDraft: props.initialBrief
123	        ? { brief: props.initialBrief.answers, confidence: {} }
124	        : null,
125	      editingField: null,
126	      draft: "",
127	      initialized: false,
128	    });
129	    const inputRef = useSignal<HTMLTextAreaElement>();
130	    const scrollerRef = useSignal<HTMLDivElement>();
131	    const clientSig = useConvexClient();
132	
133	    /**
134	     * Kick the conversation off with the AI's opening question.
135	     * The AI may answer with a question (normal) or with a synthesis
136	     * (rare — the writer has nothing yet, so this would only happen
137	     * if the writer said "synthesize" with no prior turns; we handle
138	     * it anyway).
139	     */
140	    // eslint-disable-next-line qwik/no-use-visible-task
141	    useVisibleTask$(async () => {
142	      if (store.initialized) return;
143	      store.initialized = true;
144	
145	      const opening =
146	        props.mode === "refine" ? REFINE_OPENING_QUESTION : OPENING_QUESTION;
147	
148	      // Seed the writer side with an empty reply slot for the AI
149	      // to fill. The interview always starts with the AI asking.
150	      store.messages = [{ author: "interviewer", text: opening }];
151	      // (The opening question is hard-coded — no AI call needed for
152	      // the first turn.)
153	    });
154	
155	    /**
156	     * Auto-scroll the message thread to the bottom when a new
157	     * message lands. Cheap because the thread is bounded.
158	     */
159	    // eslint-disable-next-line qwik/no-use-visible-task
160	    useVisibleTask$(({ track }) => {
161	      track(() => store.messages.length);
162	      track(() => store.synthesis);
163	      const el = scrollerRef.value;
164	      if (el) el.scrollTop = el.scrollHeight;
165	    });
166	
167	    const runTurn = $(async (writerText: string) => {
168	      store.messages = [
169	        ...store.messages,
170	        { author: "writer", text: writerText },
171	      ];
172	      store.loading = true;
173	      store.error = null;
174	
175	      try {
176	        const settings = await loadAiSettingsFromIdb();
177	        let result: InterviewTurnResult | null = null;
178	        const hasByok = hasConfiguredAiProvider(settings);
179	
180	        if (hasByok && settings) {
181	          result = await runClientInterviewTurn(
182	            {
183	              messages: store.messages,
184	              mode: props.mode,
185	              currentBrief: props.initialBrief ?? null,
186	            },
187	            settings,
188	          );
189	          if (!result) {
190	            store.error =
191	              "Your configured provider did not answer. Check the API key, model, and base URL in Preferences.";
192	            return;
193	          }
194	        }
195	
196	        if (!result && !hasByok && clientSig.value) {
197	          try {
198	            result = (await clientSig.value.action(
199	              (api as any).agents.runInterviewTurn,
200	              {
201	                messages: store.messages,
202	                mode: props.mode,
203	                currentBrief: props.initialBrief ?? null,
204	              },
205	            )) as InterviewTurnResult | null;
206	          } catch {
207	            store.error =
208	              "The shared server could not answer. Sign in again or use your own provider in Preferences.";
209	            return;
210	          }
211	        }
212	
213	        if (!result) {
214	          store.error = hasByok
215	            ? "Your configured provider did not answer. Check the API key, model, and base URL in Preferences."
216	            : "Add a provider in Preferences or sign in to use the interview.";
217	          return;
218	        }
219	
220	        if (result.kind === "question") {
221	          store.liveDraft = mergeDossierDraft(store.liveDraft, result.draft);
222	          store.messages = [
223	            ...store.messages,
224	            { author: "interviewer", text: result.text },
225	          ];
226	        } else {
227	          // Synthesis — fill any missing field with the writer's
228	          // own current answer so the dossier is never empty.
229	          const current = props.initialBrief?.answers;
230	          const brief: ProjectInterviewAnswers = {
231	            workingTitle:
232	              result.brief.workingTitle || current?.workingTitle || "",
233	            format: result.brief.format || current?.format || "",
234	            audience: result.brief.audience || current?.audience || "",
235	            goal: result.brief.goal || current?.goal || "",
236	            tone: result.brief.tone || current?.tone || "",
237	            constraints: result.brief.constraints || current?.constraints || "",
238	            successSignal:
239	              result.brief.successSignal || current?.successSignal || "",
240	          };
241	          store.synthesis = { brief, confidence: result.confidence };
242	          store.liveDraft = { brief, confidence: result.confidence };
243	        }
244	      } catch (err) {
245	        store.error =
246	          (err as Error).message ??
247	          "The interview could not continue. Check your provider settings and try again.";
248	      } finally {
249	        store.loading = false;
250	      }
251	    });
252	
253	    const send = $(async () => {
254	      if (store.loading || store.synthesis) return;
255	      const text = store.draft.trim();
256	      if (!text) return;
257	      store.draft = "";
258	      await runTurn(text);
259	    });
260	
261	    const requestSynthesis = $(async () => {
262	      if (store.loading) return;
263	      // The writer can ask for the dossier at any point. We just
264	      // send an empty-ish nudge so the model knows to synthesise
265	      // rather than ask another question.
266	      await runTurn(
267	        "(the writer is ready to see the dossier — please synthesise now)",
268	      );
269	    });
270	
271	    const acceptSynthesis = $(() => {
272	      if (!store.synthesis) return;
273	      void props.onComplete$(store.synthesis.brief);
274	    });
275	
276	    const applyEdit = $((field: keyof ProjectInterviewAnswers) => {
277	      if (!store.synthesis || !store.editingField) return;
278	      const value = store.draft.trim();
279	      if (!value) return;
280	      store.synthesis = {
281	        ...store.synthesis,
282	        brief: { ...store.synthesis.brief, [field]: value },
283	        confidence: { ...store.synthesis.confidence, [field]: "high" },
284	      };
285	      store.draft = "";
286	      store.editingField = null;
287	    });
288	
289	    const startEditing = $((field: keyof ProjectInterviewAnswers) => {
290	      if (!store.synthesis) return;
291	      store.editingField = field;
292	      store.draft = store.synthesis.brief[field] ?? "";
293	      // Focus the input next tick
294	      setTimeout(() => inputRef.value?.focus(), 0);
295	    });
296	
297	    const dismissSynthesis = $(() => {
298	      // The writer wants to keep talking. Drop the synthesis and
299	      // resume the conversation.
300	      store.synthesis = null;
301	      store.editingField = null;
302	      store.draft = "";
303	    });
304	
305	    const livePanel = store.synthesis
306	      ? { brief: store.synthesis.brief, confidence: store.synthesis.confidence }
307	      : store.liveDraft;
308	
309	    return (
310	      <div
311	        class="min-h-screen flex flex-col bg-[var(--color-paper)] text-[var(--color-ink)]"
312	        style={{ fontFamily: "var(--font-serif)" }}
313	      >
314	        {/* Header */}
315	        <header class="px-6 py-4 border-b border-[var(--color-paper-3)] bg-[var(--color-paper-2)]/90 backdrop-blur-sm flex items-center justify-between">
316	          <div>
317	            <p
318	              class="text-[0.6rem] tracking-[0.32em] uppercase text-[var(--color-ink-muted)]"
319	              style={{ fontFamily: "var(--font-typewriter)" }}
320	            >
321	              {props.mode === "refine" ? "Refine the dossier" : "The interview"}
322	            </p>
323	            <h1
324	              class="text-lg leading-tight mt-0.5"
325	              style={{ fontFamily: "var(--font-display)", fontWeight: 600 }}
326	            >
327	              {props.mode === "refine"
328	                ? "The room reads your draft."
329	                : "Begin with a one-liner."}
330	            </h1>
331	          </div>
332	          {props.onCancel$ && (
333	            <button
334	              onClick$={props.onCancel$}
335	              class="text-[var(--color-ink-muted)] hover:text-[var(--color-ink)] text-sm"
336	              style={{
337	                fontFamily: "var(--font-typewriter)",
338	                letterSpacing: "0.1em",
339	              }}
340	            >
341	              {props.cancelLabel ?? "Cancel"}
342	            </button>
343	          )}
344	        </header>
345	
346	        {/* Thread */}
347	        <div
348	          ref={scrollerRef}
349	          class="flex-1 overflow-y-auto px-4 py-6 space-y-4"
350	        >
351	          <div class="mx-auto grid max-w-6xl gap-5 lg:grid-cols-[minmax(0,1fr)_22rem]">
352	            <div class="space-y-4">
353	              {store.messages.map((m, i) => (
354	                <div
355	                  key={i}
356	                  class={`flex ${m.author === "writer" ? "justify-end" : "justify-start"}`}
357	                >
358	                  <div
359	                    class={`max-w-[80%] rounded-[3px] px-4 py-2.5 leading-relaxed text-[0.95rem] ${
360	                      m.author === "writer"
361	                        ? "bg-[var(--color-vermilion)] text-white"
362	                        : "bg-[var(--color-paper-2)] border border-[var(--color-paper-3)] text-[var(--color-ink)]"
363	                    }`}
364	                    style={{
365	                      fontFamily:
366	                        m.author === "writer"
367	                          ? "var(--font-serif)"
368	                          : "var(--font-display)",
369	                    }}
370	                  >
371	                    {m.author === "interviewer" && (
372	                      <p
373	                        class="text-[0.55rem] tracking-[0.24em] uppercase mb-1 text-[var(--color-ink-muted)]"
374	                        style={{ fontFamily: "var(--font-typewriter)" }}
375	                      >
376	                        The room
377	                      </p>
378	                    )}
379	                    {m.text}
380	                  </div>
381	                </div>
382	              ))}
383	
384	              {store.loading && (
385	                <div class="flex justify-start">
386	                  <div class="bg-[var(--color-paper-2)] border border-[var(--color-paper-3)] rounded-[3px] px-4 py-2.5">
387	                    <span
388	                      class="text-[var(--color-ink-muted)] text-sm"
389	                      style={{ fontFamily: "var(--font-typewriter)" }}
390	                    >
391	                      The room is reading…
392	                    </span>
393	                  </div>
394	                </div>
395	              )}
396	
397	              {store.synthesis && (
398	                <div class="bg-[var(--color-paper-2)] border border-[var(--color-paper-3)] rounded-[2px] p-5 shadow-sm space-y-4">
399	                  <div>
400	                    <p
401	                      class="text-[0.6rem] tracking-[0.24em] uppercase text-[var(--color-ink-muted)] mb-1"
402	                      style={{ fontFamily: "var(--font-typewriter)" }}
403	                    >
404	                      Draft dossier
405	                    </p>
406	                    <p
407	                      class="text-base"
408	                      style={{
409	                        fontFamily: "var(--font-display)",
410	                        fontWeight: 600,
411	                      }}
412	                    >
413	                      The room's first pass. Edit anything before you take it to
414	                      the desk.
415	                    </p>
416	                  </div>
417	
418	                  <dl class="space-y-3">
419	                    {FIELD_ORDER.map((field) => {
420	                      const value = store.synthesis!.brief[field];
421	                      const conf = store.synthesis!.confidence[field];
422	                      const isEditing = store.editingField === field;
423	                      return (
424	                        <div
425	                          key={field}
426	                          class="border-l-2 border-[var(--color-paper-3)] pl-3 py-1"
427	                        >
428	                          <dt
429	                            class="text-[0.6rem] tracking-[0.2em] uppercase text-[var(--color-ink-muted)] flex items-center gap-2 mb-1"
430	                            style={{ fontFamily: "var(--font-typewriter)" }}
431	                          >
432	                            <span
433	                              class={`inline-block w-1.5 h-1.5 rounded-full ${confidenceTone(conf)}`}
434	                              aria-hidden="true"
435	                            />
436	                            {FIELD_LABELS[field]}
437	                            <span
438	                              class="text-[0.55rem] tracking-[0.1em] normal-case text-[var(--color-ink-muted)]"
439	                              style={{ fontFamily: "var(--font-typewriter)" }}
440	                            >
441	                              ({confidenceLabel(conf)})
442	                            </span>
443	                          </dt>
444	                          <dd
445	                            class="text-[0.95rem] leading-relaxed"
446	                            style={{ fontFamily: "var(--font-serif)" }}
447	                          >
448	                            {isEditing ? (
449	                              <div class="space-y-2">
450	                                <textarea
451	                                  ref={inputRef}
452	                                  value={store.draft}
453	                                  onInput$={(_, el) => {
454	                                    store.draft = el.value;
455	                                  }}
456	                                  rows={3}
457	                                  class="w-full border border-[var(--color-paper-3)] rounded px-2 py-1.5 text-sm bg-[var(--color-paper-soft)] focus:outline-none focus:border-[var(--color-vermilion)]"
458	                                  style={{ fontFamily: "var(--font-serif)" }}
459	                                />
460	                                <div class="flex items-center gap-2">
461	                                  <button
462	                                    onClick$={() => applyEdit(field)}
463	                                    class="text-xs px-3 py-1 rounded bg-[var(--color-vermilion)] text-white"
464	                                    style={{
465	                                      fontFamily: "var(--font-typewriter)",
466	                                    }}
467	                                  >
468	                                    Save
469	                                  </button>
470	                                  <button
471	                                    onClick$={() => {
472	                                      store.editingField = null;
473	                                      store.draft = "";
474	                                    }}
475	                                    class="text-xs text-[var(--color-ink-muted)] hover:text-[var(--color-ink)]"
476	                                    style={{
477	                                      fontFamily: "var(--font-typewriter)",
478	                                    }}
479	                                  >
480	                                    Cancel
481	                                  </button>
482	                                </div>
483	                              </div>
484	                            ) : (
485	                              <div class="flex items-start justify-between gap-2">
486	                                <span class="flex-1">
487	                                  {value || (
488	                                    <em class="text-[var(--color-ink-muted)] italic">
489	                                      (empty — the room wasn't sure)
490	                                    </em>
491	                                  )}
492	                                </span>
493	                                <button
494	                                  onClick$={() => startEditing(field)}
